import{_ as o,o as r,c as p,a5 as c}from"./chunks/framework.B5tqjWbr.js";const u=JSON.parse('{"title":"教程 0009：单相功率因数校正（power factor correction / PFC）电流参考","description":"","frontmatter":{"title":"教程 0009：单相功率因数校正（power factor correction / PFC）电流参考","date":"2026-07-02T00:00:00.000Z","section":"电源控制","chapter":"01-Lessons","chapterTitle":"电源课程","category":"电源控制","tags":["imported"],"source":"power","sourcePath":"0009-single-phase-pfc-current-reference.html","status":"learning","visibility":"public","summary":"Imported from 0009-single-phase-pfc-current-reference.html","chapterOrder":10},"headers":[],"relativePath":"content/power/lessons/0009-single-phase-pfc-current-reference.md","filePath":"content/power/lessons/0009-single-phase-pfc-current-reference.md","lastUpdated":null}'),a={name:"content/power/lessons/0009-single-phase-pfc-current-reference.md"};function i(l,e,t,n,d,s){return r(),p("div",null,[...e[0]||(e[0]=[c(`<h1 id="教程-0009-单相功率因数校正-power-factor-correction-pfc-电流参考" tabindex="-1">教程 0009：单相功率因数校正（power factor correction / PFC）电流参考 <a class="header-anchor" href="#教程-0009-单相功率因数校正-power-factor-correction-pfc-电流参考" aria-label="Permalink to &quot;教程 0009：单相功率因数校正（power factor correction / PFC）电流参考&quot;">​</a></h1><p>中文主讲。一个概念：PFC 的第一步不是先写完整控制器，而是先知道输入电流参考应该长什么样。</p><pre><code>目录
</code></pre><ul><li><p>它是什么</p></li><li><p>为什么 UPS 需要它</p></li><li><p>物理直觉</p></li><li><p>数学形式</p></li><li><p>一个仿真任务与仿真观察</p></li><li><p>固件落地</p></li><li><p>常见误解</p></li><li><p>验收标准、复盘问题、导师问题</p></li></ul><p>**保密边界：**本节只使用公开基础理论和教学参数，不包含公司内部代码、未公开产品方案、客户项目参数或内部测试数据。</p><h2 id="_1-它是什么" tabindex="-1">1. 它是什么 <a class="header-anchor" href="#_1-它是什么" aria-label="Permalink to &quot;1. 它是什么&quot;">​</a></h2><p>功率因数校正（power factor correction / PFC）的第一步，是让输入电流尽量与交流输入电压同相、同形。</p><p>电流参考（current reference）是控制器希望输入电流跟踪的目标波形。对单相 PFC 来说，理想电流参考通常与输入电压 <code>vac</code> 同相。</p><p>本节只讲电流参考怎么生成，不展开完整电压环、电流环、锁相环（phase-locked loop / PLL）和脉宽调制（pulse-width modulation / PWM）。</p><h2 id="_2-为什么-ups-需要它" tabindex="-1">2. 为什么 UPS 需要它 <a class="header-anchor" href="#_2-为什么-ups-需要它" aria-label="Permalink to &quot;2. 为什么 UPS 需要它&quot;">​</a></h2><p>不间断电源（uninterruptible power supply / UPS）前级通常要从交流电网取电。如果输入电流畸变严重或与电压不同相，会带来：</p><ul><li><p>功率因数低，输入视在功率变大。</p></li><li><p>谐波电流增加，对电网和前级器件不友好。</p></li><li><p>整流桥、Boost 电感和母线电容的电流应力变大。</p></li></ul><p>PFC 的目标是让电网看见的负载更像电阻：电压怎么变，电流就按比例跟着变。</p><h2 id="_3-物理直觉" tabindex="-1">3. 物理直觉 <a class="header-anchor" href="#_3-物理直觉" aria-label="Permalink to &quot;3. 物理直觉&quot;">​</a></h2><p>纯电阻负载的电流与电压同相。PFC 电流参考就是让电源前级“装得像电阻”。</p><p>整流后的 Boost PFC 功率级看到的是 <code>|vac|</code>，但从电网侧看，输入电流仍应跟原始交流电压 <code>vac</code> 同相：正半周吸正电流，负半周吸负电流。</p><pre><code>交流输入
vac, 50 Hz

整流 + Boost
看到 |vac|

电流参考
iref = G * vac

目标
PF 接近 1

vac
iref 同相
</code></pre><p>图 1：本节只建立电流参考形状，不展开完整 PFC 控制器。</p><h2 id="_4-数学形式" tabindex="-1">4. 数学形式 <a class="header-anchor" href="#_4-数学形式" aria-label="Permalink to &quot;4. 数学形式&quot;">​</a></h2><p>如果目标输入功率为 <code>P</code>，交流电压的均方根值（root mean square / RMS）为 <code>Vrms</code>，可以定义等效电导：</p><p>G = P / Vrms^2 i_ref(t) = G * v_ac(t)</p><p>平均输入功率：</p><p>Pavg = mean(v_ac(t) * i_ref(t))</p><p>因为 <code>i_ref</code> 与 <code>v_ac</code> 同相，理想功率因数接近 1。</p><h2 id="_5-一个仿真任务与仿真观察" tabindex="-1">5. 一个仿真任务与仿真观察 <a class="header-anchor" href="#_5-一个仿真任务与仿真观察" aria-label="Permalink to &quot;5. 一个仿真任务与仿真观察&quot;">​</a></h2><p>一个仿真任务是运行脚本，观察 <code>vac</code>、<code>|vac|</code>、<code>iref</code> 和瞬时功率之间的关系：</p><p>cd E:\\gitee_CodeStorage\\学习\\电源 python simulations\\python\\single_phase_pfc_current_reference.py</p><p>脚本会生成并自动打开图；如果无法自动打开，会打印完整路径。图中包含输入电压、整流电压、电流参考、瞬时功率和参数框。</p><pre><code>对比实验
python simulations\\python\\single_phase_pfc_current_reference.py --target-power 500 --output simulations\\results\\pfc_current_ref_500w.png
</code></pre><p>python simulations\\python\\single_phase_pfc_current_reference.py --target-power 1500 --output simulations\\results\\pfc_current_ref_1500w.png</p><p>比较 500 W 和 1500 W 时电流参考幅值如何变化。文件名和图内参数框都写明了当前功率条件。</p><p>观察顺序：</p><ul><li><p>先看 <code>vac</code> 与 <code>iref</code> 是否同相。</p></li><li><p>看 <code>|vac|</code> 与交流电压的关系，理解整流后功率级看到的电压。</p></li><li><p>看瞬时功率是否有两倍工频脉动。</p></li><li><p>看参数框里的功率因数 <code>PF</code> 是否接近 1。</p></li></ul><h2 id="_6-固件落地" tabindex="-1">6. 固件落地 <a class="header-anchor" href="#_6-固件落地" aria-label="Permalink to &quot;6. 固件落地&quot;">​</a></h2><p>真实固件里，电流参考通常由以下信号共同决定：</p><ul><li><p>电压环输出：决定当前需要多少输入功率或电流幅值。</p></li><li><p>输入电压采样或 PLL：给出电网相位或单位正弦。</p></li><li><p>前馈和限幅：避免输入低压或启动瞬间给出过大参考。</p></li><li><p>电流环：让实际电感电流跟踪 <code>i_ref</code>。</p></li></ul><p>读 PFC 代码时，先找“电流参考在哪里生成”，再看电流环如何跟踪它。</p><h2 id="_7-常见误解" tabindex="-1">7. 常见误解 <a class="header-anchor" href="#_7-常见误解" aria-label="Permalink to &quot;7. 常见误解&quot;">​</a></h2><ul><li><p>**误解：**PFC 就是把母线电压升到 380 V。 **纠正：**升压只是功率级结果；PFC 的关键是输入电流的形状和相位。</p></li><li><p>**误解：**电流参考越大越好。 **纠正：**电流参考幅值由功率需求、输入电压、限流和母线控制共同决定。</p></li><li><p>**误解：**整流后电压为正，所以只需要考虑正电流。 **纠正：**从电网侧看，输入电流仍要与交流电压同相，正负半周都要对应。</p></li></ul><h2 id="_8-验收标准" tabindex="-1">8. 验收标准 <a class="header-anchor" href="#_8-验收标准" aria-label="Permalink to &quot;8. 验收标准&quot;">​</a></h2><ul><li><p>能解释 PFC 电流参考为什么要与 <code>vac</code> 同相。</p></li><li><p>能用 <code>G = P / Vrms^2</code> 推出 <code>i_ref = G * vac</code>。</p></li><li><p>能在图中指出 <code>vac</code>、<code>|vac|</code>、<code>iref</code> 和 <code>p(t)</code>。</p></li><li><p>能解释为什么瞬时功率有脉动，但平均功率接近目标功率。</p></li><li><p>能基于图中 PF、RMS 和功率参数准备导师问题。</p></li></ul><h2 id="_9-复盘问题" tabindex="-1">9. 复盘问题 <a class="header-anchor" href="#_9-复盘问题" aria-label="Permalink to &quot;9. 复盘问题&quot;">​</a></h2><ul><li><p>默认仿真中，<code>Vrms=220 V</code>、<code>P=1000 W</code>，电流 RMS 大约是多少？</p></li><li><p>如果目标功率从 500 W 提高到 1500 W，<code>iref</code> 幅值如何变化？</p></li><li><p>为什么本节没有直接讲完整电压环？如果电流参考都不会看，直接看双环控制会卡在哪里？</p></li></ul><h2 id="_10-导师问题" tabindex="-1">10. 导师问题 <a class="header-anchor" href="#_10-导师问题" aria-label="Permalink to &quot;10. 导师问题&quot;">​</a></h2><ul><li><p>我用 <code>single_phase_pfc_current_reference.py</code> 看到 <code>iref = G * vac</code> 时 PF 接近 1。公司单相 PFC 代码里的电流参考是直接用输入电压采样生成，还是通过 PLL/单位正弦生成？</p></li><li><p>本节用 <code>P / Vrms^2</code> 得到等效电导。真实工程里电流参考幅值通常来自电压环输出、功率指令，还是前馈计算？</p></li><li><p>图中瞬时功率有两倍工频脉动。公司工程里母线电压环如何避免跟着二倍频纹波乱调？</p></li></ul><p>**下一步：**下一节再讲 PFC 电压环如何给出电流幅值，不要把电压环、电流环、PLL 和 PWM 一次混在一起。</p><p>关联：<a href="./0008-boost-telemetry-fault-log.html">上一节：Boost 慢速任务、遥测与故障日志</a>；源稿：<code>concepts/power-electronics/single-phase-pfc-current-reference.md</code>。</p><pre><code>上一节：教程 0008：Boost 慢速任务、遥测与故障日志
下一节：教程 0010：单相功率因数校正（power factor correction / PFC）电压环如何生成电流幅值
</code></pre>`,48)])])}const _=o(a,[["render",i]]);export{u as __pageData,_ as default};
